class Solution {
public:
    int findIntegers(int n) {
        int dp[32] = {0};
        dp[0] = 1;
        dp[1] = 2;
        for (int i = 2; i < 31; ++i) {
            dp[i] = dp[i - 1] + dp[i - 2];
        }

        int result = 0;
        int prev_bit = 0;
        for (int i = 29; i >= 0; --i) {
            int mask = 1 << i;
            int bit = (n & mask) >> i;
            if (bit == 1) {
                result += dp[i];
                if (prev_bit == 1) {
                    return result;
                }
                prev_bit = 1;
            } else {
                prev_bit = 0;
            }
        }

        return result + 1;
    }
};

